3	const MIN_NEIGHBORS_TO_SURVIVE = 2;
4	const MAX_NEIGHBORS_TO_SURVIVE = 3;
5	const NEIGHBORS_TO_REPRODUCE = 3;
6	
7	const NEIGHBOR_OFFSETS: Cell[] = [
8	  [-1, -1], [0, -1], [1, -1],
9	  [-1, 0], [1, 0],
10	  [-1, 1], [0, 1], [1, 1],
11	];
12	
13	const SELF_AND_NEIGHBOR_OFFSETS: Cell[] = [[0, 0], ...NEIGHBOR_OFFSETS];
14	
15	const keyOf = (x: number, y: number): string => `${x},${y}`;
16	
17	const willLive = (alive: boolean, neighbors: number): boolean =>
18	  alive
19	    ? neighbors >= MIN_NEIGHBORS_TO_SURVIVE &&
20	      neighbors <= MAX_NEIGHBORS_TO_SURVIVE
21	    : neighbors === NEIGHBORS_TO_REPRODUCE;
22	
23	export function nextGeneration(cells: Cell[]): Cell[] {
24	  const isAlive = (x: number, y: number): boolean =>
25	    cells.some(([cx, cy]) => cx === x && cy === y);
26	
27	  const countNeighbors = (x: number, y: number): number =>
28	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
29	
30	  const candidates = new Map<string, Cell>();
31	  for (const [x, y] of cells) {
32	    for (const [dx, dy] of SELF_AND_NEIGHBOR_OFFSETS) {
33	      const nx = x + dx;
34	      const ny = y + dy;
35	      candidates.set(keyOf(nx, ny), [nx, ny]);
36	    }
37	  }
38	
39	  return [...candidates.values()].filter(([x, y]) =>
40	    willLive(isAlive(x, y), countNeighbors(x, y))
41	  );
42	}
