8	    expect(nextGeneration([])).toEqual([]);
9	  });
10	  it("should kill a single live cell (0 neighbors) — [(0,0)] → []", () => {
11	    expect(nextGeneration([[0, 0]])).toEqual([]);
12	  });
13	  it("should kill both cells under underpopulation — [(0,1),(1,1)] → []", () => {
14	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
15	  });
16	  it("should let a cell with 2 or 3 neighbors survive (survival)", () => {
17	    // Blinker bar: live center (0,1) has 2 live neighbors → survives
18	    const next = nextGeneration([[0, 0], [0, 1], [0, 2]]);
19	    expect(next).toContainEqual([0, 1]);
20	  });
21	  it("should kill a cell with more than 3 neighbors (overpopulation)", () => {
22	    // Rule 3 example: center (1,1) has 4 live neighbors (> 3) → dies
23	    const next = nextGeneration([
