25	      [1, 1],
26	      [0, 2], [1, 2], [2, 2],
27	    ]);
28	    expect(next).not.toContainEqual([1, 1]);
29	  });
30	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
31	    // Rule 4 example: dead cell (1,1) has exactly 3 live neighbors → becomes alive
32	    const next = nextGeneration([[0, 0], [1, 0], [0, 1]]);
33	    expect(next).toContainEqual([1, 1]);
34	  });
