42	    const byCoord = (a: Cell, b: Cell) => a[0] - b[0] || a[1] - b[1];
43	    const next = nextGeneration([[0, 0], [0, 1], [0, 2]]);
44	    const expected: Cell[] = [[-1, 1], [0, 1], [1, 1]];
45	    expect([...next].sort(byCoord)).toEqual([...expected].sort(byCoord));
46	  });
47	  it("should handle negative coordinates", () => {
48	    const byCoord = (a: Cell, b: Cell) => a[0] - b[0] || a[1] - b[1];
49	    // Blinker entirely in negative space: vertical bar → horizontal bar
